package com.example.trackerinmobile.data.model.auth

import kotlinx.serialization.SerialName
import kotlinx.serialization.Serializable

@Serializable
data class LoginRequest(
    val email: String,
    val password: String
)

@Serializable
data class RegisterRequest(
    val name: String,
    val email: String,
    val password: String,
    @SerialName("password_confirmation")
    val passwordConfirmation: String
)
// Tambahan field untuk menyesuaikan request di RegisterScreen (misal DOB, Status, dsb) bisa ditambahkan jika disupport backend.
// Namun api docs hanya menyebut name, email, password, password_confirmation.
// Untuk saat ini kita petakan saja name ke username atau fullName.

@Serializable
data class GoogleAuthRequest(
    val token: String
)

@Serializable
data class AuthResponse(
    val message: String? = null,
    @SerialName("access_token")
    val accessToken: String,
    val user: User
)

@Serializable
data class User(
    val id: Int,
    val name: String,
    val email: String
)

package com.example.trackerinmobile.data.model.auth

import kotlinx.serialization.SerialName
import kotlinx.serialization.Serializable

@Serializable
data class LoginRequest(
    val email: String,
    val password: String
)

@Serializable
data class RegisterRequest(
    val name: String,
    val email: String,
    val password: String,
    @SerialName("password_confirmation")
    val passwordConfirmation: String
)
// Tambahan field untuk menyesuaikan request di RegisterScreen (misal DOB, Status, dsb) bisa ditambahkan jika disupport backend.
// Namun api docs hanya menyebut name, email, password, password_confirmation.
// Untuk saat ini kita petakan saja name ke username atau fullName.

@Serializable
data class GoogleAuthRequest(
    val token: String
)

@Serializable
data class AuthResponse(
    val message: String? = null,
    @SerialName("access_token")
    val accessToken: String,
    @SerialName("token_type")
    val tokenType: String? = null,
    val data: User
)

@Serializable
data class User(
    val id: Int,
    val name: String,
    val email: String,
    @SerialName("google_id")
    val googleId: String? = null,
    @SerialName("email_verified_at")
    val emailVerifiedAt: String? = null,
    @SerialName("created_at")
    val createdAt: String? = null,
    @SerialName("updated_at")
    val updatedAt: String? = null
)

package com.example.trackerinmobile.core

import androidx.lifecycle.ViewModel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import java.util.UUID

data class Todo(
    val id: String = UUID.randomUUID().toString(),
    val title: String,
    val isCompleted: Boolean = false
)

class TodoViewModel : ViewModel() {
    private val _todos = MutableStateFlow<List<Todo>>(
        listOf(
            Todo(title = "Do your homework"),
            Todo(title = "Finish UI Project"),
            Todo(title = "Review Computer Networks Task")
        )
    )
    val todos: StateFlow<List<Todo>> = _todos.asStateFlow()

    fun addTodo(title: String) {
        val current = _todos.value.toMutableList()
        current.add(Todo(title = title))
        _todos.value = current
    }

    fun toggleTodoCompleted(id: String) {
        val current = _todos.value.toMutableList()
        val index = current.indexOfFirst { it.id == id }
        if (index != -1) {
            val todo = current[index]
            current[index] = todo.copy(isCompleted = !todo.isCompleted)
            _todos.value = current
        }
    }

    fun updateTodo(id: String, newTitle: String) {
        val current = _todos.value.toMutableList()
        val index = current.indexOfFirst { it.id == id }
        if (index != -1) {
            val todo = current[index]
            current[index] = todo.copy(title = newTitle)
            _todos.value = current
        }
    }

    fun deleteTodo(id: String) {
        val current = _todos.value.toMutableList()
        current.removeAll { it.id == id }
        _todos.value = current
    }
}

package com.example.trackerinmobile.core

import androidx.lifecycle.ViewModel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import java.util.UUID

data class Todo(
    val id: String = UUID.randomUUID().toString(),
    val title: String,
    val description: String = "",
    val dueDate: String = "",
    val isCompleted: Boolean = false
)

class TodoViewModel : ViewModel() {
    private val _todos = MutableStateFlow<List<Todo>>(
        listOf(
            Todo(
                title = "Konfigurasi Database",
                description = "Melakukan konfigurasi Database menggunakan PHP agar bisa terhubung ke microsoft azure",
                dueDate = "Deadline 6/7/2026"
            ),
            Todo(
                title = "Membuat Fungsi Otomasisasi",
                description = "Buat fungsi di php untuk otomasisasi input dan output data dari database ke program.",
                dueDate = "Deadline 7/7/2026"
            ),
            Todo(
                title = "Membuat Tampilan Data",
                description = "Buat tampilan untuk menampilkan data dari database agar bisa dilihat oleh user",
                dueDate = "Deadline 10/7/2026"
            )
        )
    )
    val todos: StateFlow<List<Todo>> = _todos.asStateFlow()

    fun addTodo(title: String, description: String = "", dueDate: String = "") {
        val current = _todos.value.toMutableList()
        current.add(Todo(title = title, description = description, dueDate = dueDate))
        _todos.value = current
    }

    fun toggleTodoCompleted(id: String) {
        val current = _todos.value.toMutableList()
        val index = current.indexOfFirst { it.id == id }
        if (index != -1) {
            val todo = current[index]
            current[index] = todo.copy(isCompleted = !todo.isCompleted)
            _todos.value = current
        }
    }

    fun updateTodo(id: String, newTitle: String, newDesc: String = "", newDueDate: String = "") {
        val current = _todos.value.toMutableList()
        val index = current.indexOfFirst { it.id == id }
        if (index != -1) {
            val todo = current[index]
            current[index] = todo.copy(title = newTitle, description = newDesc, dueDate = newDueDate)
            _todos.value = current
        }
    }

    fun deleteTodo(id: String) {
        val current = _todos.value.toMutableList()
        current.removeAll { it.id == id }
        _todos.value = current
    }
}

package com.example.trackerinmobile.ui.components

import androidx.compose.foundation.background
